// StartDm is the resolver for the startDM field.
func (r *mutationResolver) StartDm(ctx context.Context, input model.StartDMInput) (*corev1.Room, error) {
	user, err := requireAuth(ctx)
	if err != nil {
		return nil, err
	}

	// Authorization: DMs piggyback on message.post.
	can, err := r.core.CanStartDM(ctx, user.Id)
	if err != nil {
		return nil, err
	}
	if !can {
		return nil, core.ErrPermissionDenied
	}

	// Find or create the DM room (actor is automatically included as participant)
	room, _, err := r.core.FindOrCreateDM(ctx, user.Id, input.ParticipantIds)
	if err != nil {
		return nil, err
	}

	return room, nil
}
